SELECT id, title, content, category, author, cover_image, created_at, updated_at
FROM articles


        AND category = #{category}


ORDER BY created_at DESC
LIMIT #{offset}, #{limit}

SELECT id, title, content, category, author, cover_image, created_at, updated_at
FROM articles
WHERE id = #{id}

SELECT id, title, content, category, author, cover_image, created_at, updated_at
FROM articles
WHERE category = #{category} AND id != #{excludeId}
ORDER BY created_at DESC
LIMIT #{limit}
